for fname, sections in translations.items():
    with open(fname) as f:
        data = json.load(f)
    data.update(sections)
    with open(fname, 'w') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f'{fname} updated successfully')
